export const DISPLAY_NAME_MAX_LENGTH = 48;

export function isValidDisplayName(value: string): boolean {
  const normalized = value.trim();

  return (
    normalized.length >= 1 &&
    normalized.length <= DISPLAY_NAME_MAX_LENGTH &&
    /^[\p{L}\p{M} .'-]+$/u.test(normalized)
  );
}

describe("display name contract", () => {
  it.each([
    "Ana-Maria O'Neill",
    "Jos\u00e9 Alvarez",
    "\u5c71\u7530 \u592a\u90ce"
  ])("accepts supported names: %s", (name) => {
    expect(isValidDisplayName(name)).toBe(true);
  });

  it("accepts exactly 48 characters", () => {
    expect(isValidDisplayName("A".repeat(48))).toBe(true);
  });

  it("rejects 49 characters", () => {
    expect(isValidDisplayName("A".repeat(49))).toBe(false);
  });
});
